import{_ as e,o as l,c as i,ag as t}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"MailYou","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/index.md","filePath":"zh/guide/index.md","lastUpdated":1773655718000}'),o={name:"zh/guide/index.md"};function r(d,a,h,u,n,c){return l(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="mailyou" tabindex="-1">MailYou <a class="header-anchor" href="#mailyou" aria-label="Permalink to &quot;MailYou&quot;">​</a></h1><p>MailYou 是一个本地优先的桌面邮箱客户端，适合希望邮件体验更安静、更贴近桌面的人。</p><h2 id="为桌面工作流而做" tabindex="-1">为桌面工作流而做 <a class="header-anchor" href="#为桌面工作流而做" aria-label="Permalink to &quot;为桌面工作流而做&quot;">​</a></h2><p>项目使用 Vue 构建界面，Electron 负责桌面集成，Rust 负责邮件协议与本地存储。目标很直接：让邮箱体验更舒适，同时把数据尽量留在设备本地。</p><h2 id="添加邮箱" tabindex="-1">添加邮箱 <a class="header-anchor" href="#添加邮箱" aria-label="Permalink to &quot;添加邮箱&quot;">​</a></h2><p>MailYou 的添加流程尽量保持简短：</p><ul><li>从邮箱地址开始</li><li>命中已知域名时自动套用预设</li><li>仅在服务商支持时显示 OAuth</li><li>仅在没有预设或开启高级模式时显示服务器细节</li></ul><h2 id="认证方式" tabindex="-1">认证方式 <a class="header-anchor" href="#认证方式" aria-label="Permalink to &quot;认证方式&quot;">​</a></h2><p>MailYou 支持两种 OAuth 路径：</p><ul><li>使用本地 <code>client_id</code> 与 <code>client_secret</code> 直连服务商</li><li>使用内置默认地址和桌面 token 的 MailYou OAuth 代理</li></ul><p>如果服务商不支持 OAuth，则回退为标准密码登录。</p><h2 id="隐私方向" tabindex="-1">隐私方向 <a class="header-anchor" href="#隐私方向" aria-label="Permalink to &quot;隐私方向&quot;">​</a></h2><p>MailYou 以本地桌面存储为基础，不把自己定位为托管邮箱或云同步服务。</p><p>法律文档已发布在本站：</p><ul><li><a href="/zh/legal/privacy-policy.html">隐私政策</a></li><li><a href="/zh/legal/terms-of-service.html">服务条款</a></li></ul>',15)])])}const _=e(o,[["render",r]]);export{p as __pageData,_ as default};
